const body = $input.first().json.body || $input.first().json;
const event = body;
const subscription = event?.data?.object || {};

const cancellationReason = subscription.cancellation_details?.reason || '';
const isForced = cancellationReason === 'payment_failed';

if (!isForced) {
  return [{ json: { skip: true, reason: 'Not a forced cancellation', cancellationReason } }];
}

const customerId = subscription.customer || '';
const subscriptionId = subscription.id || '';
const cancelledAt = subscription.canceled_at
  ? new Date(subscription.canceled_at * 1000).toISOString()
  : new Date().toISOString();

// Get latest invoice amount if available
const latestInvoice = subscription.latest_invoice || null;
const amountOwed = subscription.items?.data?.[0]?.price?.unit_amount || 0;
const currency = (subscription.items?.data?.[0]?.price?.currency || 'usd').toUpperCase();
const amountOwedDisplay = amountOwed ? `$${(amountOwed / 100).toFixed(2)} ${currency}` : 'outstanding balance';

return [{ json: {
  customerId,
  subscriptionId,
  cancellationReason,
  cancelledAt,
  amountOwed,
  amountOwedDisplay,
  currency,
  latestInvoice,
  skip: false,
  updatedAt: new Date().toISOString(),
  rawPayload: JSON.stringify(body)
} }];

const users = $input.first().json;
const user = Array.isArray(users) ? users[0] : users;
const parsed = $('Parse Forced Cancellation Payload').first().json;

const planDisplayNames = { free: 'Free', starter: 'Starter', pro: 'Pro', scale: 'Scale' };
const planTier = user?.plan_tier || 'starter';
const planDisplay = planDisplayNames[planTier] || planTier;

return [{ json: {
  ...parsed,
  email: user?.email || '',
  firstName: user?.first_name || 'there',
  planTier,
  planDisplay
} }];

